* {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

html,
body {
  width: 100%;
  height: 100%;
  overflow: hidden;
  font-family: "Segoe UI", Roboto, Arial, sans-serif;
  background: #f8fafc;
}

/* ===========================
   LAYOUT
=========================== */
.login-layout {
  width: 100vw;
  height: 100vh;
  display: flex;
  background: #f8fafc;
}

/* ===========================
   LEFT PANEL
=========================== */
.left-panel {
  flex: 1.1;
  position: relative;
  display: flex;
  justify-content: center;
  align-items: center;
  overflow: hidden;
  background: linear-gradient(135deg, #2563eb 0%, #1d4ed8 55%, #1e3a8a 100%);
}

/* Decorative circles */
.bg-circle {
  position: absolute;
  border-radius: 50%;
  background: rgba(255, 255, 255, 0.06);
  animation: float 10s ease-in-out infinite;
}

.circle-1 {
  width: 520px;
  height: 520px;
  top: -170px;
  right: -150px;
}

.circle-2 {
  width: 340px;
  height: 340px;
  left: -120px;
  bottom: -120px;
}

.circle-3 {
  width: 170px;
  height: 170px;
  right: 140px;
  bottom: 130px;
}

@keyframes float {
  0% {
    transform: translateY(0px);
  }
  50% {
    transform: translateY(-18px);
  }
  100% {
    transform: translateY(0px);
  }
}
/* ===========================
   HERO
=========================== */
.hero {
  position: relative;
  z-index: 2;
  width: 460px;
  max-width: 90%;
  color: white;
}

.hero-logo {
  width: 96px;
  height: 96px;
  border-radius: 24px;
  background: white;
  color: #2563eb;
  display: flex;
  justify-content: center;
  align-items: center;
  font-size: 34px;
  font-weight: 700;
  margin-bottom: 38px;
  box-shadow: 0 18px 45px rgba(0, 0, 0, 0.18);
}

.hero h1 {
  font-size: 50px;
  line-height: 1.15;
  font-weight: 700;
  margin-bottom: 18px;
}

.subtitle {
  font-size: 20px;
  opacity: 0.95;
  font-weight: 500;
}

.hero-divider {
  width: 90px;
  height: 4px;
  border-radius: 999px;
  background: white;
  margin: 35px 0;
}

.description {
  font-size: 17px;
  line-height: 1.8;
  opacity: 0.88;
  max-width: 390px;
}

/* ===========================
   RIGHT PANEL
=========================== */
.right-panel {
  flex: 0.9;
  display: flex;
  justify-content: center;
  align-items: center;
  padding: 50px;
  background: white;
}

/* ===========================
   CARD
=========================== */
.card {
  width: 100%;
  max-width: 430px;
  padding: 45px;
  background: white;
  border-radius: 26px;
  box-shadow: 0 25px 70px rgba(15, 23, 42, 0.08);
  animation: fadeUp 0.55s ease;
}

@keyframes fadeUp {
  from {
    opacity: 0;
    transform: translateY(24px);
  }
  to {
    opacity: 1;
    transform: none;
  }
}
/* ===========================
   BRAND
=========================== */
.brand {
  text-align: center;
  margin-bottom: 36px;
}

.logo {
  width: 68px;
  height: 68px;
  margin: auto auto 20px;
  display: flex;
  justify-content: center;
  align-items: center;
  border-radius: 18px;
  background: linear-gradient(135deg, #2563eb, #1d4ed8);
  color: white;
  font-size: 24px;
  font-weight: 700;
  box-shadow: 0 12px 28px rgba(37, 99, 235, 0.3);
}

.brand h1 {
  font-size: 30px;
  font-weight: 700;
  color: #1e293b;
  margin-bottom: 8px;
}

.brand p {
  color: #64748b;
  font-size: 14px;
}

/* ===========================
   INPUT
=========================== */
.field {
  position: relative;
  margin-bottom: 22px;
}

.input-icon {
  position: absolute;
  left: 16px;
  top: 17px;
  font-size: 16px;
  opacity: 0.55;
}

.field input {
  width: 100%;
  padding: 17px 46px 10px 46px;
  border: 1.6px solid #dbe3ee;
  border-radius: 12px;
  background: white;
  color: #1e293b;
  outline: none;
  transition: border-color 0.2s, box-shadow 0.2s;
  font-size: 14px;
}

.field input:focus {
  border-color: #2563eb;
  box-shadow: 0 0 0 4px rgba(37, 99, 235, 0.1);
}

.field label {
  position: absolute;
  left: 44px;
  top: 16px;
  padding: 0 4px;
  background: white;
  color: #64748b;
  pointer-events: none;
  transition: 0.2s;
}

.field input:focus + label,
.field input.filled + label {
  top: -8px;
  left: 40px;
  font-size: 11px;
  color: #2563eb;
}

.toggle-pw {
  position: absolute;
  top: 16px;
  right: 16px;
  cursor: pointer;
  user-select: none;
  font-size: 17px;
  transition: 0.2s;
}

.toggle-pw:hover {
  transform: scale(1.08);
}

/* ===========================
   ERROR
=========================== */
.error-text {
  color: #dc2626;
  font-size: 13px;
  min-height: 18px;
  margin: -6px 0 16px;
}

/* ===========================
   BUTTON
=========================== */
.submit {
  width: 100%;
  padding: 15px;
  border: none;
  border-radius: 12px;
  background: linear-gradient(135deg, #2563eb, #1d4ed8);
  color: white;
  font-size: 15px;
  font-weight: 600;
  cursor: pointer;
  display: flex;
  justify-content: center;
  align-items: center;
  gap: 8px;
  transition: transform 0.15s, box-shadow 0.2s;
  box-shadow: 0 12px 30px rgba(37, 99, 235, 0.28);
}

.submit:hover {
  transform: translateY(-2px);
}

.submit:active {
  transform: scale(0.98);
}

.submit:disabled {
  opacity: 0.75;
  cursor: not-allowed;
}

/* ===========================
   SPINNER
=========================== */
.spinner {
  width: 16px;
  height: 16px;
  border: 2px solid rgba(255, 255, 255, 0.35);
  border-top-color: white;
  border-radius: 50%;
  display: none;
  animation: spin 0.7s linear infinite;
}

.spinner.show {
  display: inline-block;
}

@keyframes spin {
  to {
    transform: rotate(360deg);
  }
}
/* ===========================
   FOOTER
=========================== */
.footer {
  margin-top: 34px;
  text-align: center;
  color: #94a3b8;
  font-size: 12px;
  line-height: 1.6;
}

/* ===========================
   SHAKE
=========================== */
.field.shake {
  animation: shake 0.35s;
}

@keyframes shake {
  25% {
    transform: translateX(-5px);
  }
  50% {
    transform: translateX(5px);
  }
  75% {
    transform: translateX(-3px);
  }
}
/* ===========================
   RESPONSIVE
=========================== */
@media (max-width: 900px) {
  .left-panel {
    display: none;
  }
  .right-panel {
    flex: 1;
    padding: 24px;
  }
  .card {
    max-width: 420px;
    padding: 36px;
    box-shadow: none;
  }
}

