appsmith.onReady(function () {
  const usernameEl = document.getElementById('username');
  const passwordEl = document.getElementById('password');
  const form = document.getElementById('loginForm');
  const errorText = document.getElementById('errorText');
  const togglePw = document.getElementById('togglePw');
  usernameEl.focus();
  function syncFilledState(el) {
    if (el.value) el.classList.add('filled');else el.classList.remove('filled');
  }
  function updateModel() {
    appsmith.updateModel({
      username: usernameEl.value.trim(),
      password: passwordEl.value
    });
  }
  usernameEl.addEventListener('input', function () {
    syncFilledState(usernameEl);
    updateModel();
  });
  passwordEl.addEventListener('input', function () {
    syncFilledState(passwordEl);
    updateModel();
  });
  togglePw.addEventListener('click', function () {
    const isPw = passwordEl.type === 'password';
    passwordEl.type = isPw ? 'text' : 'password';
    togglePw.textContent = isPw ? 'Sembunyi' : 'Lihat';
  });
  function shake(el) {
    el.classList.add('shake');
    setTimeout(function () {
      el.classList.remove('shake');
    }, 350);
  }
  form.addEventListener('submit', function (e) {
    e.preventDefault();
    errorText.textContent = '';
    if (!usernameEl.value.trim()) {
      shake(document.getElementById('fieldUsername'));
      errorText.textContent = 'Username wajib diisi';
      usernameEl.focus();
      return;
    }
    if (!passwordEl.value) {
      shake(document.getElementById('fieldPassword'));
      errorText.textContent = 'Password wajib diisi';
      passwordEl.focus();
      return;
    }
    updateModel();
    appsmith.triggerEvent('onLoginSubmit');
  });
});
appsmith.onModelChange(function (model) {
  const submitBtn = document.getElementById('submitBtn');
  const spinner = document.getElementById('spinner');
  const submitLabel = document.getElementById('submitLabel');
  if (!submitBtn) return; // widget belum selesai render, model sempat berubah lebih dulu

  const loading = !!model.isLoading;
  submitBtn.disabled = loading;
  spinner.classList.toggle('show', loading);
  submitLabel.textContent = loading ? 'Memproses...' : 'Masuk';
});

